#include<bits/stdc++.h>
using namespace std;
char s[200010];
int main()
{
    int n,m;
    scanf("%d%d%s",&n,&m,s+1);
    for(int i=1;i<=m;i++)
    {
        char c;
        cin>>c;
        int x;
        scanf("%d",&x);
        if(n==m&&i==1)
        {
            s[x]='W';
            continue;
        }
        s[x]=c;
    }
    for(int i=1;i<=n;i++)
    {
        if(s[i]=='M')
        {
            if(s[i-1]=='B'||s[i-1]=='W')
            {
                s[i]=s[i-1];
            }
        }
        else if(s[i]=='R')
        {
            if(s[i-1]=='B'||s[i-1]=='W')
            {
                s[i]='B'+'W'-s[i-1];
            }
        }
    }
    for(int i=n;i>=1;i--)
    {
        if(s[i]=='M')
        {
            if(s[i+1]=='B'||s[i+1]=='W')
            {
                s[i]=s[i+1];
            }
        }
        else if(s[i]=='R')
        {
            if(s[i+1]=='B'||s[i+1]=='W')
            {
                s[i]='B'+'W'-s[i+1];
            }
        }
    }
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        if(s[i]!=s[i-1])
        {
            ans++;
        }
    }
    printf("%d",ans);
    return 0;
}
